"use client"

import { useState, useRef, useEffect } from "react"
import {
  Plus,
  Mic,
  ChevronDown,
  ArrowRight,
  Monitor,
  Scissors,
  Ruler,
  BookOpen,
  Briefcase
} from "lucide-react"

export default function Home() {
  const [input, setInput] = useState("")
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  // 自动调整输入框高度
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto"
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`
    }
  }, [input])

  return (
    // 外层容器：占满剩余高度，居中对齐排版
    <div className="flex flex-col h-full w-full items-center pt-[15vh] px-4 md:px-8 relative bg-[#111111]">

      {/* 1. 顶部大 Logo / 品牌名 */}
      <h1 className="text-4xl md:text-5xl font-normal text-zinc-200 tracking-wider mb-8 font-serif">
        方圆之间
      </h1>

      {/* 2. 核心大输入框 (高仿 Perplexity 样式) */}
      <div className="w-full max-w-3xl bg-[#1e1e1e] border border-zinc-700/50 rounded-2xl p-3 flex flex-col shadow-lg focus-within:border-zinc-500 focus-within:bg-[#222222] transition-all duration-300">
        <textarea
          ref={textareaRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="问任何关于工业制版的问题..."
          className="w-full bg-transparent border-none outline-none resize-none text-zinc-200 placeholder:text-zinc-500 px-2 pt-2 pb-6 min-h-[60px] text-lg max-h-[200px] overflow-y-auto"
          rows={1}
        />

        {/* 输入框底部工具栏 */}
        <div className="flex justify-between items-center mt-2">
          {/* 左侧：附件与聚焦模式 */}
          <div className="flex items-center gap-2">
            <button
              className="p-1.5 bg-[#2a2a2a] hover:bg-[#333333] text-zinc-400 hover:text-zinc-200 rounded-full transition-colors flex items-center justify-center"
              title="添加文件或图片"
            >
              <Plus size={18} />
            </button>
            <button className="flex items-center gap-1.5 px-3 py-1.5 bg-[#2a2a2a] hover:bg-[#333333] text-zinc-400 hover:text-zinc-200 rounded-full text-sm font-medium transition-colors">
              <Monitor size={16} />
              <span>智能体</span>
              <Plus size={14} className="opacity-50" />
            </button>
          </div>

          {/* 右侧：模型选择与发送 */}
          <div className="flex items-center gap-1">
            <button className="flex items-center gap-1 px-3 py-1.5 text-zinc-400 hover:text-zinc-200 rounded-full text-sm font-medium transition-colors">
              模型 <ChevronDown size={14} />
            </button>
            <button className="p-2 text-zinc-400 hover:bg-[#2a2a2a] hover:text-zinc-200 rounded-full transition-colors">
              <Mic size={18} />
            </button>
            <button
              className={`p-2 rounded-full transition-all duration-300 flex items-center justify-center ml-1 ${input.trim()
                ? 'bg-zinc-200 text-black hover:bg-white scale-100 opacity-100'
                : 'bg-[#2a2a2a] text-zinc-500 scale-95 opacity-50 cursor-not-allowed'
                }`}
            >
              <ArrowRight size={18} strokeWidth={2.5} />
            </button>
          </div>
        </div>
      </div>

      {/* 3. 底部建议区域 (高仿 Perplexity 试用面板) */}
      <div className="w-full max-w-3xl mt-6 bg-transparent border border-zinc-800/80 rounded-2xl p-5">
        <div className="flex items-center gap-2 text-zinc-400 text-sm font-medium mb-4">
          <Monitor size={16} />
          <span>试用 工业制版专家</span>
        </div>

        {/* 建议分类按钮 (横向滚动) */}
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide mb-4">
          <SuggestionPill icon={<Scissors size={14} />} label="样板缩水率" />
          <SuggestionPill icon={<Ruler size={14} />} label="领口放码" />
          <SuggestionPill icon={<Briefcase size={14} />} label="实战案例" />
          <SuggestionPill icon={<BookOpen size={14} />} label="学习课程" />
        </div>

        {/* 建议问题列表 */}
        <div className="flex flex-col gap-3.5 text-sm text-zinc-400">
          <div className="hover:text-zinc-200 cursor-pointer transition-colors">
            计算西装领口 2% 缩水率的精确换算公式
          </div>
          <div className="hover:text-zinc-200 cursor-pointer transition-colors">
            女装袖口收尖规程中的腋下堆量如何处理？
          </div>
          <div className="hover:text-zinc-200 cursor-pointer transition-colors">
            帮我整理一份男裤立裆换算的工业标准化表格
          </div>
          <div className="hover:text-zinc-200 cursor-pointer transition-colors">
            分析连袖结构中产生腋下折痕的几何原理
          </div>
        </div>
      </div>

      {/* 底部版权或说明小字 (可选) */}
      <div className="absolute bottom-6 text-xs text-zinc-600">
        方圆智版 AI 工业级极简打版计算与建议
      </div>
    </div>
  )
}

// 提取一个小组件用于渲染建议的胶囊按钮
function SuggestionPill({ icon, label }: { icon: React.ReactNode; label: string }) {
  return (
    <button className="flex items-center gap-2 px-4 py-2 border border-zinc-800 rounded-full text-xs font-medium text-zinc-300 hover:bg-[#2a2a2a] hover:text-white transition-colors whitespace-nowrap">
      {icon}
      {label}
    </button>
  )
}